```c
#include <SDL2/SDL.h>
#include <stdio.h>

int main(int argc, char* args[]) {

    SDL_Window* window = NULL;
    SDL_Surface* screenSurface = NULL;
    SDL_Surface* imageSurface = NULL;

    if (SDL_Init(SDL_INIT_VIDEO) < 0) {
        printf("SDL could not initialize! SDL_Error: %s\n", SDL_GetError());
        return 1;
    }

    window = SDL_CreateWindow("Hello World!", SDL_WINDOWPOS_UNDEFINED, SDL_WINDOWPOS_UNDEFINED, 640, 480, SDL_WINDOW_SHOWN);
    if (window == NULL) {
        printf("Window could not be created! SDL_Error: %s\n", SDL_GetError());
        return 1;
    }

    screenSurface = SDL_GetWindowSurface(window);

    // 加载图片
    imageSurface = SDL_LoadBMP("res/test.png");
    if (imageSurface == NULL) {
        printf("Unable to load image %s! SDL Error: %s\n", "res/test.png", SDL_GetError());
        return 1;
    }

    SDL_BlitSurface(imageSurface, NULL, screenSurface, NULL);
    SDL_UpdateWindowSurface(window);
    SDL_Delay(3000);

    SDL_DestroyWindow(window);
    SDL_Quit();

    return 0;
}
```

请注意，为了加载PNG文件，需要安装SDL_image库。如果未安装，可以使用以下命令安装：

```bash
sudo apt-get install libsdl2-image-dev
```

